@* Vertical sidebar navigation for settings sections *@

<nav class="nav nav-pills flex-column settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="nav-link text-start @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
            <span class="me-2">@GetIcon(section)</span>
            @section
        </button>
    }
</nav>

@code {
    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "Profile";

    [Parameter]
    public EventCallback<string> OnSectionChanged { get; set; }

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_2b7e6d2006f8417698f1d706eaa02c38.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="text-center">
                <label class="form-label fw-semibold d-block">Avatar Preview</label>
                <div class="mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle border" style="width:120px;height:120px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="rounded-circle border bg-secondary d-inline-flex align-items-center justify-content-center"
                             style="width:120px;height:120px;">
                            <span class="text-white fs-1">👤</span>
                        </div>
                    }
                </div>
                <small class="text-muted text-break">@_avatarUrl</small>
                <div class="mt-2">
                    <input type="text" class="form-control form-control-sm" placeholder="Avatar URL" @bind="_avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Saved state for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _statusMessage = null;
    }
}

@using sv_2b7e6d2006f8417698f1d706eaa02c38.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notification Preferences</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Channel Muting</h6>
            <p class="text-muted small">Select channels to mute. Muted channels won't send notifications.</p>

            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = prefs.MutedChannels.ToList();
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _statusMessage = "Notification preferences saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_2b7e6d2006f8417698f1d706eaa02c38.Services

<div class="card mb-4">
    <div class="card-header">
        <h6 class="mb-0">Active Sessions</h6>
    </div>
    <div class="card-body p-0">
        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted p-3 mb-0">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td class="text-end">
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </div>
</div>

@* Confirmation Dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter]
    public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var elapsed = DateTime.UtcNow - lastActive;
        return elapsed.TotalMinutes < 1 ? "Just now"
            : elapsed.TotalMinutes < 60 ? $"{(int)elapsed.TotalMinutes}m ago"
            : elapsed.TotalHours < 24 ? $"{(int)elapsed.TotalHours}h ago"
            : $"{(int)elapsed.TotalDays}d ago";
    }
}

@using sv_2b7e6d2006f8417698f1d706eaa02c38.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnPasswordChanged="HandlePasswordChangeAsync" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                            <text>Your account is protected with 2FA.</text>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark me-1">Disabled</span>
                            <text>Enable 2FA for additional security.</text>
                        }
                    </p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="_sessions"
                         CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                         OnRevoke="HandleRevokeAsync" />
}

@code {
    private bool _loading = true;
    private string? _statusMessage;
    private bool _isError;

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task HandlePasswordChangeAsync()
