@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    <div class="btn-group" role="group">
                        @foreach (var size in _fontSizes)
                        {
                            <button type="button"
                                    class="btn @(_fontSize == size ? "btn-primary" : "btn-outline-primary")"
                                    @onclick="() => _fontSize = size">
                                @size
                            </button>
                        }
                    </div>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            Compact Mode
                            <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top:1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBgClass" style="@PreviewStyle; transition: all 0.3s ease;">
                    <h5 style="@PreviewFontStyle">Sample Heading</h5>
                    <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                        This is how your content will look with the selected appearance settings.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                        <button class="btn btn-sm @PreviewBtnClass">Primary</button>
                        <button class="btn btn-sm @PreviewBtnOutlineClass">Secondary</button>
                    </div>
                    <div class="@PreviewCardClass @(_compactMode ? "p-2" : "p-3") rounded">
                        <small style="@PreviewFontStyle">
                            📋 A sample card element with <strong>@_language</strong> locale
                            and <strong>@_fontSize</strong> font size.
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            await SettingsService.SaveAppearanceAsync(
                new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
            _statusMessage = "Appearance settings saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    // Preview computed properties
    private bool IsDark => _theme == "Dark";

    private string PreviewBgClass => IsDark ? "text-white" : "";

    private string PreviewStyle
    {
        get
        {
            var bg = IsDark ? "background-color:#1e1e2e;color:#cdd6f4;" : "background-color:#ffffff;color:#333;";
            return bg;
        }
    }

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewBtnClass => IsDark ? "btn-light" : "btn-primary";
    private string PreviewBtnOutlineClass => IsDark ? "btn-outline-light" : "btn-outline-primary";
    private string PreviewCardClass => IsDark ? "bg-dark border border-secondary" : "bg-light";
}

