            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword"
                       @oninput="ValidatePasswords" />
                @if (_passwordMismatch)
                {
                    <div class="text-danger small mt-1">Passwords do not match.</div>
                }
            </div>
            <button class="btn btn-warning" @onclick="SubmitAsync"
                    disabled="@(!CanSubmit)">
                @if (_submitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback OnPasswordChanged { get; set; }

    private bool _expanded;
    private bool _submitting;
    private string? _statusMessage;
    private bool _isError;
    private bool _passwordMismatch;

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    private bool CanSubmit =>
        !_submitting
        && !string.IsNullOrWhiteSpace(_currentPassword)
        && !string.IsNullOrWhiteSpace(_newPassword)
        && _newPassword == _confirmPassword;

    private void ValidatePasswords(ChangeEventArgs e)
    {
        _confirmPassword = e.Value?.ToString() ?? "";
        _passwordMismatch = !string.IsNullOrEmpty(_confirmPassword)
                            && _newPassword != _confirmPassword;
    }

    private async Task SubmitAsync()
    {
        if (!CanSubmit) return;

        _submitting = true;
        _statusMessage = null;
        try
        {
            await OnPasswordChanged.InvokeAsync();
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to change password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _submitting = false;
        }
    }
}
