                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            Compact Mode
                            <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top:1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBgClass" style="@PreviewStyle; transition: all 0.3s ease;">
                    <h5 style="@PreviewFontStyle">Sample Heading</h5>
                    <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                        This is how your content will look with the selected appearance settings.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                        <button class="btn btn-sm @PreviewBtnClass">Primary</button>
                        <button class="btn btn-sm @PreviewBtnOutlineClass">Secondary</button>
                    </div>
                    <div class="@PreviewCardClass @(_compactMode ? "p-2" : "p-3") rounded">
                        <small style="@PreviewFontStyle">
                            📋 A sample card element with <strong>@_language</strong> locale
                            and <strong>@_fontSize</strong> font size.
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
