    private bool IsDark => _theme == "Dark";

    private string PreviewBgClass => IsDark ? "text-white" : "";

    private string PreviewStyle
    {
        get
        {
            var bg = IsDark ? "background-color:#1e1e2e;color:#cdd6f4;" : "background-color:#ffffff;color:#333;";
            return bg;
        }
    }

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewBtnClass => IsDark ? "btn-light" : "btn-primary";
    private string PreviewBtnOutlineClass => IsDark ? "btn-outline-light" : "btn-outline-primary";
    private string PreviewCardClass => IsDark ? "bg-dark border border-secondary" : "bg-light";
}
