+            await OnPasswordChanged.InvokeAsync();
+            _statusMessage = "Password updated successfully!";
+            _isError = false;
+            _currentPassword = "";
+            _newPassword = "";
+            _confirmPassword = "";
+        }
+        catch (Exception ex)
+        {
+            _statusMessage = $"Failed to change password: {ex.Message}";
+            _isError = true;
+        }
+        finally
+        {
+            _submitting = false;
+        }
+    }
+}
