@using sv_2b7e6d2006f8417698f1d706eaa02c38.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <ChangePasswordPanel OnPasswordChanged="HandlePasswordChangeAsync" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                            <text>Your account is protected with 2FA.</text>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark me-1">Disabled</span>
                            <text>Enable 2FA for additional security.</text>
                        }
                    </p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="_sessions"
                         CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                         OnRevoke="HandleRevokeAsync" />
}

@code {
    private bool _loading = true;
    private string? _statusMessage;
    private bool _isError;

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task HandlePasswordChangeAsync()
    {
        // The ChangePasswordPanel handles its own UX; we just call the service
        await SettingsService.ChangePasswordAsync("", "");
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeAsync(string sessionId)
    {
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
            _statusMessage = "Session revoked successfully.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _isError = true;
        }
    }
}

