@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <aside class="settings-nav">
        <h5 class="px-3 py-2 mb-1 text-muted">⚙️ Settings</h5>
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionChanged="section => _activeSection = section" />
    </aside>

    <section class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </section>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

.settings-nav {
    flex: 0 0 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar .nav-link {
    border-radius: 0.375rem;
    margin-bottom: 0.25rem;
    color: #495057;
    font-weight: 500;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

